const b = $input.item.json.body || $input.item.json;
return [{ json: {
  message: b.message || '',
  audio: b.audio || '',
  audio_format: b.audio_format || '',
  history: b.history || [],
  sessionId: b.sessionId || 'default',
  context: b.context || {},
  hasAudio: !!b.audio
}}];

const prev = $('Estrai Dati').item.json;
const audioB64 = prev.audio;

// Decode base64 to binary buffer
const binaryData = Buffer.from(audioB64, 'base64');

// Determine extension from format
const fmt = prev.audio_format || 'audio/webm';
let ext = 'webm';
if (fmt.includes('mp4')) ext = 'mp4';
if (fmt.includes('ogg')) ext = 'ogg';
if (fmt.includes('wav')) ext = 'wav';

// Set binary property for Whisper
return [{
  json: prev,
  binary: {
    audioFile: {
      data: audioB64,
      mimeType: fmt.split(';')[0] || 'audio/webm',
      fileName: 'voice.' + ext
    }
  }
}];

const prev = $('Estrai Dati').item.json;
const whisperResult = $input.item.json;
const transcription = whisperResult.text || '';
if (!transcription) throw new Error('Trascrizione vuota');
return [{ json: {
  message: transcription,
  transcription: transcription,
  history: prev.history,
  sessionId: prev.sessionId,
  context: prev.context
}}];

const input = $input.item.json;
return [{ json: {
  message: input.message,
  transcription: '',
  history: input.history,
  sessionId: input.sessionId,
  context: input.context
}}];

const input = $input.item.json;
const ctx = input.context || {};
const hist = input.history || [];

// Build conversation messages
const historyText = hist.slice(-20).map(h => h.role + ': ' + h.content).join('\n');

// Build context summary
const clientsStr = (ctx.clients || []).map(c => c.n + ' (' + c.e + ') [id:' + c.id + ']' + (c.p ? ' tel:' + c.p : '')).join('\n');
const todayStr = (ctx.today_appts || []).map(a => a.time + ' - ' + a.type + ' - ' + a.client + ' (' + a.status + ')').join('\n') || 'Nessun appuntamento oggi.';
const wlStr = (ctx.waitlist || []).map(w => '#' + (w.pos||'?') + ' ' + w.n + ' (priorità: ' + (w.pri == 1 ? 'urgente' : 'normale') + ')').join('\n') || 'Lista vuota.';

const systemPrompt = `Sei l'assistente personale di Irene, tatuatrice professionista (Irene Gipsy Tattoo, Roma).
Il tuo nome è "Assistente Irene". Rispondi SEMPRE in italiano.

PERSONALITA':
- Professionale, concisa, efficiente
- Usa qualche emoji ma senza esagerare (max 1-2 per messaggio)
- Risposte brevi e dirette, max 3-4 frasi per messaggi informativi

DATA ODIERNA: ${ctx.date || new Date().toISOString().slice(0,10)}

CLIENTI REGISTRATI (${(ctx.clients||[]).length}):
${clientsStr || 'Nessun cliente.'}

APPUNTAMENTI DI OGGI:
${todayStr}

LISTA D'ATTESA:
${wlStr}

RICHIESTE IN SOSPESO: ${ctx.pending_wl_requests || 0} lista attesa, ${ctx.pending_rsch_requests || 0} cambio data

COSA PUOI FARE:
1. CERCARE CLIENTI: cerca nella lista clienti per nome/email e mostra le info
2. CREARE APPUNTAMENTI: raccogli dati (cliente, tipo, data, ora) e proponi l'azione
3. INVIARE MESSAGGI: email, WhatsApp, SMS tramite il sistema di messaggistica
4. GESTIRE LISTA D'ATTESA: mostra stato, approva/rifiuta richieste
5. MOSTRARE STATISTICHE: appuntamenti del giorno, clienti totali, ecc.

CREAZIONE APPUNTAMENTI — PROCEDURA OBBLIGATORIA:
- Chiedi: chi (nome cliente), tipo (consulenza/pre-seduta/seduta), data e ora
- Se il cliente non è in lista, dì a Irene di crearlo prima dalla sezione Clienti
- Se ci sono più clienti con lo stesso nome, mostra la lista e chiedi quale
- Quando hai TUTTI i dati, mostra il riepilogo e chiedi conferma
- IMPORTANTE: nella risposta con il riepilogo, aggiungi alla fine un blocco JSON nascosto con questo formato esatto:
  <!--ACTION:{"type":"create_appointment","data":{"client_id":"...","client_name":"...","client_email":"...","client_phone":"...","appointment_type":"consulenza|pre-seduta|seduta","scheduled_at":"ISO8601","notes":"...","location":"in_studio|videochiamata","is_first_session":false}}-->
- Per consulenza/pre-seduta chiedi anche la modalità: in studio o videochiamata
- La data deve essere nel formato ISO 8601 (es: 2026-04-25T14:00:00)

INVIO MESSAGGI — PROCEDURA:
- Chiedi: destinatario (nome cliente), canale (email/whatsapp/sms), contenuto del messaggio
- Per email chiedi anche l'oggetto
- Mostra anteprima e chiedi conferma
- Nel riepilogo aggiungi:
  <!--ACTION:{"type":"send_message","data":{"channel":"email|whatsapp|sms","to_email":"...","to_phone":"...","subject":"...","message":"...","client_name":"..."}}-->

REGOLE ACTION:
- Il blocco <!--ACTION:...--> va SEMPRE alla fine del messaggio, dopo il testo visibile
- Inseriscilo SOLO quando hai tutti i dati e stai chiedendo conferma
- NON inserirlo quando stai ancora raccogliendo informazioni
- Il JSON deve essere valido e su una riga sola

REGOLE IMPORTANTI:
- Se non trovi un cliente, suggerisci nomi simili dalla lista
- Non inventare dati — usa solo quelli forniti nel contesto
- Se Irene chiede qualcosa che non puoi fare, dillo chiaramente
- Per orari appuntamenti suggerisci orari lavorativi (10:00-19:00, lun-ven)
`;

const messages = [
  { role: 'system', content: systemPrompt },
];

// Add history
hist.slice(-16).forEach(h => {
  messages.push({ role: h.role === 'assistant' ? 'assistant' : 'user', content: h.content });
});

// Add current message
messages.push({ role: 'user', content: input.message });

return [{ json: { messages, transcription: input.transcription || '' } }];

const prev = $('Costruisci Prompt').item.json;
const oai = $input.item.json;

let reply = 'Mi dispiace, c\'è stato un errore. Riprova.';
let action = null;

if (oai.choices && oai.choices[0] && oai.choices[0].message) {
  reply = oai.choices[0].message.content || reply;
}

// Extract ACTION block if present
const actionMatch = reply.match(/<!--ACTION:(\{.*?\})-->/);
if (actionMatch) {
  try {
    action = JSON.parse(actionMatch[1]);
  } catch (e) {
    // Invalid JSON in action block, ignore
  }
  // Remove the action block from visible reply
  reply = reply.replace(/<!--ACTION:\{.*?\}-->/, '').trim();
}

const result = { reply };
if (prev.transcription) result.transcription = prev.transcription;
if (action) result.action = action;

return [{ json: result }];
